import{_ as a,c as i,o as t,aj as s}from"./chunks/framework.BlveriQe.js";const p=JSON.parse('{"title":"Admin Console","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/admin-console.md","filePath":"getting-started/admin-console.md"}'),n={name:"getting-started/admin-console.md"};function l(r,e,o,h,c,d){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="admin-console" tabindex="-1">Admin Console <a class="header-anchor" href="#admin-console" aria-label="Permalink to “Admin Console”">​</a></h1><p>The Primitive Admin Console is a web-based dashboard for managing your apps, users, and backend configuration. It&#39;s available at <a href="https://admin.primitiveapi.com" target="_blank" rel="noreferrer">admin.primitiveapi.com</a>.</p><h2 id="what-you-can-do" tabindex="-1">What You Can Do <a class="header-anchor" href="#what-you-can-do" aria-label="Permalink to “What You Can Do”">​</a></h2><h3 id="app-configuration" tabindex="-1">App Configuration <a class="header-anchor" href="#app-configuration" aria-label="Permalink to “App Configuration”">​</a></h3><ul><li>View and update app settings (name, mode, allowed origins)</li><li>Manage <a href="./app-secrets.html">app secrets</a> (values write-only — never displayed after saving) and non-secret <a href="./app-secrets.html#config-vars">config vars</a> (values shown in plain text)</li><li>Configure authentication providers (Google OAuth credentials, Magic Link, OTP, Passkeys)</li><li>Manage email templates for authentication flows</li><li>Set invite-only mode for controlled access</li><li>Manage the per-app whitelist for <code>+primitivetest</code> automated-testing sign-ins (see <a href="./authentication.html#test-user-sign-in-for-automated-testing">Authentication</a>)</li></ul><h3 id="users-groups" tabindex="-1">Users &amp; Groups <a class="header-anchor" href="#users-groups" aria-label="Permalink to “Users &amp; Groups”">​</a></h3><ul><li>View all users in your app</li><li>Invite new users and manage pending invitations</li><li>Enable member invitations and set quota limits</li><li>View pending invitations and the email-based document shares or group adds attached to them</li><li>Manage console admins (who can access the admin console) and admin invitations</li><li>Manage waitlist (when in invite-only mode)</li></ul><h3 id="sharing-access" tabindex="-1">Sharing &amp; Access <a class="header-anchor" href="#sharing-access" aria-label="Permalink to “Sharing &amp; Access”">​</a></h3><ul><li>Review and approve/deny pending document access requests</li><li>Browse a user&#39;s owned and shared documents</li><li>View audit trail of share, invitation, and access-request activity</li></ul><h3 id="databases" tabindex="-1">Databases <a class="header-anchor" href="#databases" aria-label="Permalink to “Databases”">​</a></h3><ul><li>Browse databases and their types</li><li>View and test registered operations</li><li>Inspect operation <a href="./access-control.html">access rules</a> and per-subscription filter rules</li><li>Grant group-based permissions on a database</li><li>Run operations directly to verify behavior</li></ul><h3 id="workflows" tabindex="-1">Workflows <a class="header-anchor" href="#workflows" aria-label="Permalink to “Workflows”">​</a></h3><ul><li>View workflow definitions and their status (draft, active, archived)</li><li>Manage cron triggers (create, edit, enable/disable, fire manually)</li><li>Start workflow runs with test inputs</li><li>Monitor run progress and inspect step-by-step output</li><li>View run history and debug failures</li></ul><h3 id="prompts" tabindex="-1">Prompts <a class="header-anchor" href="#prompts" aria-label="Permalink to “Prompts”">​</a></h3><ul><li>View managed prompts and their configurations</li><li>Preview rendered prompts with test inputs</li><li>Run prompt test cases</li><li>Manage prompt status (draft, active, archived)</li></ul><h3 id="integrations" tabindex="-1">Integrations <a class="header-anchor" href="#integrations" aria-label="Permalink to “Integrations”">​</a></h3><ul><li>Configure external API connections (base URL, allowed paths, headers)</li><li>Manage integration secrets</li><li>Test integrations with sample requests</li><li>View recent call logs</li></ul><h3 id="email-templates" tabindex="-1">Email Templates <a class="header-anchor" href="#email-templates" aria-label="Permalink to “Email Templates”">​</a></h3><ul><li>Manage the built-in email templates (the full type list is in the <a href="./primitive-cli.html#email-templates">CLI reference</a>)</li><li>Register custom email template types with arbitrary kebab-case names</li><li>Preview rendered templates and send test emails</li></ul><h3 id="blob-buckets" tabindex="-1">Blob Buckets <a class="header-anchor" href="#blob-buckets" aria-label="Permalink to “Blob Buckets”">​</a></h3><ul><li>Create and configure blob buckets (access policy, retention tier, access rules)</li><li>Browse blobs and generate signed URLs for inspection</li><li>Delete buckets and their contents</li></ul><h3 id="analytics" tabindex="-1">Analytics <a class="header-anchor" href="#analytics" aria-label="Permalink to “Analytics”">​</a></h3><ul><li>View usage metrics and event counts</li><li>Monitor daily active users</li><li>Track custom events</li><li>See <a href="./analytics.html">Analytics</a> for the emit and query APIs that feed this view</li></ul><h2 id="when-to-use-the-console-vs-the-cli" tabindex="-1">When to Use the Console vs. the CLI <a class="header-anchor" href="#when-to-use-the-console-vs-the-cli" aria-label="Permalink to “When to Use the Console vs. the CLI”">​</a></h2><p>Both tools manage the same configuration. In practice, many developers use the console for exploring and testing, and the CLI (with <code>primitive sync</code>) for managing configuration as code — see <a href="./configuring-primitive-services.html#console-or-code">Console or Code?</a> for the full breakdown.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><ul><li><strong><a href="./primitive-cli.html">Primitive CLI</a></strong> — The command-line side of the same configuration</li><li><strong><a href="./workflows.html">Workflows</a></strong> — Define the workflows you&#39;ll test in the console</li><li><strong><a href="./api-integrations.html">API Integrations</a></strong> — Configure the integrations you&#39;ll manage in the console</li><li><strong><a href="./analytics.html">Analytics</a></strong> — Emit and query the events that show up under Analytics</li></ul>',27)])])}const u=a(n,[["render",l]]);export{p as __pageData,u as default};
